class HashMap {
    constructor() {
        this.map = new Array(100);
    }

    _hash(key) {
        let total = 0;
        for (let char of String(key)) {
            total += char.charCodeAt(0);
        }
        return total % this.map.length;
    }

    set(key, value) {
        const index = this._hash(key);
        if (!this.map[index]) {
            this.map[index] = [];
        }
        const entry = this.map[index].find(item => item[0] === key);
        if (entry) {
            entry[1] = value;
        } else {
            this.map[index].push([key, value]);
        }
    }

    get(key) {
        const index = this._hash(key);
        const bucket = this.map[index];
        if (bucket) {
            const entry = bucket.find(item => item[0] === key);
            return entry ? entry[1] : undefined;
        }
        return undefined;
    }

    delete(key) {
        const index = this._hash(key);
        const bucket = this.map[index];
        if (bucket) {
            const entryIndex = bucket.findIndex(item => item[0] === key);
            if (entryIndex !== -1) {
                bucket.splice(entryIndex, 1);
                return true;
            }
        }
        return false;
    }
