function infixToPostfix(infix) {
    const precedence = {'+': 1, '-': 1, '*': 2, '/': 2, '^': 3};
    const output = [];
    const stack = [];

    for (let token of infix.replace(/\s/g, '')) {
        if (/[a-zA-Z0-9]/.test(token)) {
