function tsp(distances) {
    const n = distances.length;
    const memo = new Array(1 << n).fill(null).map(() => new Array(n).fill(Infinity));

    for (let i = 0; i < n; i++) {
        memo[1 << i][i] = 0;
    }

    for (let mask = 1; mask < (1 << n); mask++) {
        for (let i = 0; i < n; i++) {
            if (!(mask & (1 << i))) continue;

            for (let j = 0; j < n; j++) {
                if (i === j || !(mask & (1 << j))) continue;

                const prevMask = mask ^ (1 << i);
                memo[mask][i] = Math.min(
                    memo[mask][i], 
                    memo[prevMask][j] + distances[j][i]
                );
            }
        }
    }

    return Math.min(...memo[(1 << n) - 1]);
}
