class VM {
  constructor() {
    this.memory = new Array(256).fill(0);
    this.registers = new Array(8).fill(0);
    this.pc = 0;
    this.stack = [];
  }

  fetch() {
    return this.memory[this.pc++];
  }

  execute(instruction) {
    const opcode = instruction >> 4;
    const operand = instruction & 0x0F;

    switch(opcode) {
      case 0x1: // LOAD
        this.registers[operand] = this.fetch();
        break;
      case 0x2: // ADD
        this.registers[0] += this.registers[operand];
        break;
      case 0x3: // JUMP
        this.pc = operand;
        break;
      case 0x4: // PUSH
        this.stack.push(this.registers[operand]);
        break;
      case 0x5: // POP
        this.registers[operand] = this.stack.pop();
        break;
    }
  }

  run(program) {
    this.memory.set(program);
    while (this.pc < program.length) {
      const instruction = this.fetch();
      this.execute(instruction);
    }
  }
}
