class FordFulkerson {
    constructor(graph) {
        this.graph = graph;
        this.V = graph.length;
    }

    bfs(s, t, parent) {
        let visited = new Array(this.V).fill(false);
        let queue = [s];
        visited[s] = true;
        parent[s] = -1;

        while (queue.length) {
            let u = queue.shift();
            for (let v = 0; v < this.V; v++) {
                if (!visited[v] && this.graph[u][v] > 0) {
                    queue.push(v);
                    parent[v] = u;
                    visited[v] = true;
                }
            }
        }
        return visited[t];
    }

    maxFlow(source, sink) {
        let parent = new Array(this.V);
        let maxFlow = 0;

        while (this.bfs(source, sink, parent)) {
            let pathFlow = Infinity;
            for (let v = sink; v !== source; v = parent[v]) {
                let u = parent[v];
                pathFlow = Math.min(pathFlow, this.graph[u][v]);
            }

            for (let v = sink; v !== source; v = parent[v]) {
                let u = parent[v];
                this.graph[u][v] -= pathFlow;
                this.graph[v][u] += pathFlow;
            }

            maxFlow += pathFlow;
        }
        return maxFlow;
