class SearchEngine {
  constructor(documents) {
    this.index = {};
    this.documents = documents;
    this.buildIndex();
  }

  buildIndex() {
    this.documents.forEach((doc, docId) => {
      const words = doc.toLowerCase().split(/\W+/);
      words.forEach(word => {
        if (!this.index[word]) this.index[word] = new Set();
        this.index[word].add(docId);
      });
    });
  }

  search(query) {
    const words = query.toLowerCase().split(/\W+/);
    return words.flatMap(word => 
      Array.from(this.index[word] || [])
    ).filter((docId, i, arr) => arr.indexOf(docId) === i);
  }
}

