function createMiddleware() {
  const middleware = [];

  function use(fn) {
    middleware.push(fn);
    return this;
  }

  async function execute(context) {
    for (const fn of middleware) {
      await fn(context, async () => {
        const next = middleware[middleware.indexOf(fn) + 1];
        return next ? await next(context, next) : null;
      });
    }
    return context;
  }

  return { use, execute };
}

