class LockFreeQueue {
  constructor() {
    this.head = { value: null, next: null };
    this.tail = this.head;
  }

  enqueue(value) {
    const newNode = { value, next: null };
    let currentTail, currentNext;
    do {
      currentTail = this.tail;
      currentNext = currentTail.next;
      if (currentTail === this.tail) {
        if (currentNext === null) {
          if (Atomics.compareExchange(currentTail, 'next', null, newNode) === null) {
            Atomics.compareExchange(this, 'tail', currentTail, newNode);
            return true;
          }
        } else {
          Atomics.compareExchange(this, 'tail', currentTail, currentNext);
        }
      }
    } while (true);
  }

  dequeue() {
    let currentHead, currentTail, currentNext;
    do {
      currentHead = this.head;
      currentTail = this.tail;
      currentNext = currentHead.next;
      if (currentHead === this.head) {
        if (currentHead === currentTail) {
          if (currentNext === null) return null;
          Atomics.compareExchange(this, 'tail', currentTail, currentNext);
        } else {
          const value = currentNext.value;
          if (Atomics.compareExchange(this, 'head', currentHead, currentNext) === currentHead) {
            return value;
          }
        }
      }
    } while (true);
