  const newChars = newStr.split('');
  const changes = [];
  let i = 0, j = 0;

  while (i < oldChars.length || j < newChars.length) {
    if (oldChars[i] !== newChars[j]) {
      if (newChars[j]) {
        changes.push({ type: 'add', index: j, value: newChars[j] });
        j++;
      } else {
        changes.push({ type: 'remove', index: i });
        i++;
      }
    } else {
      i++;
      j++;
    }
  }

  return changes;
}

