function geneticAlgorithm(populationSize, generations, fitnessFunc, crossoverFunc, mutationFunc) {
  let population = Array.from({length: populationSize}, () => generateRandomChromosome());

  for (let gen = 0; gen < generations; gen++) {
    let fitness = population.map(fitnessFunc);
    let parents = selectParents(population, fitness);
    let offspring = [];

    while (offspring.length < populationSize) {
      let [parent1, parent2] = parents.splice(0, 2);
      let child = crossoverFunc(parent1, parent2);
      mutationFunc(child);
      offspring.push(child);
    }

    population = offspring;
  }

