class Semaphore {
  constructor(max) {
    this.max = max;
    this.count = max;
    this.waiting = [];
  }

  acquire() {
    return new Promise((resolve) => {
      if (this.count > 0) {
        this.count--;
        resolve();
      } else {
        this.waiting.push(resolve);
      }
    });
  }

  release() {
