```javascript
class DecisionTreeNode {
  constructor(feature = null, threshold = null, left = null, right = null, value = null) {
    this.feature = feature;
    this.threshold = threshold;
    this.left = left;
    this.right = right;
    this.value = value;
  }

  predict(sample) {
    if (this.value !== null) return this.value;
    return sample[this.feature] <= this.threshold 
      ? this.left.predict(sample) 
      : this.right.predict(sample);
  }
}

class DecisionTree {
  constructor(maxDepth = 5) {
    this.maxDepth = maxDepth;
    this.root = null;
  }

  entropy(labels) {
    const counts = {};
    labels.forEach(label => counts[label] = (counts[label] || 0) + 1);
    return -Object.values(counts).map(count => {
      const p = count / labels.length;
      return p > 0 ? p * Math.log2(p) : 0;
    }).reduce((a, b) => a - b, 0);
  }

  buildTree(data, labels, depth = 0) {
    if (depth >= this.maxDepth || new Set(labels).size === 1) {
      const majorityClass = labels.reduce((a, b) => 
        labels.filter(v => v === a).length >= labels.filter(v => v === b).length ? a : b
      );
      return new DecisionTreeNode(null, null, null, null, majorityClass);
    }

    let bestGain = -Infinity;
    let bestFeature = null;
    let bestThreshold = null;

    for (let feature = 0; feature < data[0].length; feature++) {
      const values = data.map(row => row[feature]);
      const uniqueValues = [...new Set(values)];

      for (const threshold of uniqueValues) {
        const leftIndices = data.map((row, i) => row[feature] <= threshold ? i : -1).filter(i => i !== -1);
        const rightIndices = data.map((row, i) => row[feature] > threshold ? i : -1).filter(i => i !== -1);

        const leftLabels = leftIndices.map(i => labels[i]);
        const rightLabels = rightIndices.map(i => labels[i]);

        const gain = this.entropy(labels) - 
          (leftLabels.length / labels.length * this.entropy(leftLabels) + 
           rightLabels.length / labels.length * this.entropy(rightLabels));

        if (gain > bestGain) {
          bestGain = gain;
          bestFeature = feature;
          bestThreshold = threshold;
        }
      }
    }

    const leftIndices = data.map((row, i) => row[bestFeature] <= bestThreshold ? i : -1).filter(i => i !== -1);
    const rightIndices = data.map((row, i) => row[bestFeature] > bestThreshold ? i : -1).filter(i => i !== -1);

    const node = new DecisionTreeNode(
      bestFeature, 
      bestThreshold, 
      this.buildTree(leftIndices.map(i => data[i]), leftIndices.map(i => labels[i]), depth + 1),
      this.buildTree(rightIndices.map(i => data[i]), rightIndices.map(i => labels[i]), depth + 1)
    );

    return node;
  }

  train(data, labels) {
    this.root = this.buildTree(data, labels);
  }

  predict(sample) {
    return this.root.predict(sample);
  }
}
```
